using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Routing;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using System.Text.Json;

namespace MyApp.Services;

internal static class ISyncServiceServerExtensions
{
    internal static IEndpointRouteBuilder MapISyncServiceEndpoints(
        this IEndpointRouteBuilder endpoints)
    {
        var group = endpoints.MapGroup("/api/functions/sync");

        group.MapPost("/Process",
            (ISyncService service) =>
            {
                var result = service.Process();
                return Results.Ok(result);
            })
            .WithName("ISyncService_Process");

        return endpoints;
    }
}
